// Business Plan Analysis for the incoming project
const { projectId, stageKey, executionId, subStage } = $input.first().json.body;

const businessPlan = {
  targetAudience: {
    primary: "Mid-market SaaS companies (50-500 employees)",
    secondary: "Enterprise teams exploring automation",
    painPoints: [
      "Manual workflow orchestration is time-consuming and error-prone",
      "Existing tools lack domain-specific intelligence",
      "Integration fatigue across disconnected platforms"
    ],
    buyerPersonas: [
      { role: "VP of Engineering", motivation: "Reduce operational overhead", budget: "$50k-200k/yr" },
      { role: "Head of Product", motivation: "Accelerate time-to-market", budget: "$30k-100k/yr" }
    ]
  },
  pricingPosture: {
    model: "usage-based with tier floors",
    tiers: [
      { name: "Starter", price: "$49/mo", included: "5 workflows, 1000 executions" },
      { name: "Growth", price: "$199/mo", included: "25 workflows, 10000 executions" },
      { name: "Enterprise", price: "Custom", included: "Unlimited workflows, SLA, dedicated support" }
    ],
    competitivePosition: "15-30% below enterprise incumbents, premium to open-source self-hosted"
  },
  featurePhases: [
    { phase: 1, name: "Core Platform", timeline: "0-3 months", features: ["Workflow builder", "Webhook integrations", "Basic monitoring"] },
    { phase: 2, name: "Intelligence Layer", timeline: "3-6 months", features: ["AI-powered suggestions", "Auto-optimization", "Anomaly detection"] },
    { phase: 3, name: "Enterprise", timeline: "6-12 months", features: ["SSO/SAML", "Audit logging", "Custom SLA", "On-prem option"] }
  ],
  revenueModel: {
    year1: { mrr: "$15k-50k", customers: "30-100", strategy: "PLG with sales assist" },
    year2: { mrr: "$100k-300k", customers: "200-500", strategy: "Sales-led enterprise expansion" },
    breakeven: "Month 14-18",
    unitEconomics: { cac: "$1,200", ltv: "$8,400", ltvCacRatio: 7.0 }
  },
  recommendation: {
    decision: "proceed",
    confidence: 0.82,
    summary: "Strong market opportunity with clear monetization path. Usage-based pricing aligns incentives. PLG motion reduces CAC. Main risk is enterprise sales cycle length.",
    keyRisks: [
      "Enterprise sales cycles may extend runway requirements",
      "Open-source alternatives could compress pricing",
      "Feature scope creep in Phase 2 intelligence layer"
    ]
  }
};

return {
  json: {
    projectId,
    stageKey,
    executionId,
    subStage: subStage || 'business_plan',
    businessPlanResult: businessPlan
  }
};
